// Verify X-Hub-Signature-256 (handoff §7) then extract leadgen ids.
// Requires n8n env NODE_FUNCTION_ALLOW_BUILTIN=crypto
const crypto = require('crypto');
const APP_SECRET = '__META_APP_SECRET__';
const item = $input.first();
const raw = await this.helpers.getBinaryDataBuffer(0, 'data');
const sig = String((item.json.headers || {})['x-hub-signature-256'] || '');
const expected = 'sha256=' + crypto.createHmac('sha256', APP_SECRET).update(raw).digest('hex');
let ok = false;
try { ok = sig.length === expected.length && crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected)); } catch (e) { ok = false; }
if (!ok) { throw new Error('Invalid X-Hub-Signature-256 — request dropped'); }
const body = JSON.parse(raw.toString('utf8'));
const out = [];
for (const entry of body.entry || []) {
  for (const ch of entry.changes || []) {
    if (ch.field === 'leadgen' && ch.value && ch.value.leadgen_id) {
      out.push({ json: { leadgenId: String(ch.value.leadgen_id), pageId: String(ch.value.page_id || entry.id || '') } });
    }
  }
}
return out;

// Flatten Meta field_data into fun_leads columns.
const j = $json;
const fields = {};
for (const f of j.field_data || []) fields[f.name] = String((f.values || [])[0] ?? '').trim();
const pick = (...needles) => {
  for (const n of needles) {
    const k = Object.keys(fields).find(x => x.toLowerCase().includes(n));
    if (k && fields[k]) return fields[k];
  }
  return null;
};
let phone = pick('phone', 'เบอร์');
if (phone) phone = phone.replace(/[^0-9+]/g, '').replace(/^\+66/, '0');
const extra = Object.entries(fields).map(([k, v]) => k + ': ' + v).join('\n');
return { json: {
  source: 'facebook',
  leadgenId: j.id || $('Verify Signature + Extract').item.json.leadgenId,
  pageId: $('Verify Signature + Extract').item.json.pageId,
  customerName: pick('full_name', 'name', 'ชื่อ'),
  phone: phone,
  modelInterest: pick('model', 'รุ่น', 'car'),
  budgetRange: pick('budget', 'งบ'),
  rawMessage: extra || null
} };

// Merge channel row + lead fields and build the UPSERT (dedupe policy §3:
// repeat inquiry must NOT fail — reopen instead).
const ch = $json;
const lead = $('Flatten Lead').item.json;
const esc = v => (v === null || v === undefined || v === '') ? 'NULL' : "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
const sql = "INSERT INTO fun_leads (source, fb_leadgen_id, fb_page_id, brand, branch_code, customer_name, phone, model_interest, budget_range, raw_message, status, consent_flag, consent_date, next_followup_date) VALUES (" + [esc('facebook'), esc(lead.leadgenId), esc(lead.pageId), esc(ch.brand), esc(ch.branch_code), esc(lead.customerName), esc(lead.phone), esc(lead.modelInterest), esc(lead.budgetRange), esc(lead.rawMessage)].join(', ') + ", 'new', 1, NOW(), CURDATE()) ON DUPLICATE KEY UPDATE status='new', next_followup_date=CURDATE(), updated_at=NOW(), fb_leadgen_id=VALUES(fb_leadgen_id), lead_id=LAST_INSERT_ID(lead_id)";
return { json: { ...lead, brand: ch.brand, branchCode: ch.branch_code, fbPageName: ch.fb_page_name, lineGroupId: ch.line_group_id, gsheetId: ch.gsheet_id, sql: sql } };

// affectedRows: 1 = new lead, 2 = duplicate key hit → reopen.
let base = null;
try { base = $('Assemble FB').item.json; } catch (e) { /* walk-in path */ }
if (!base) { try { base = $('Assemble Walk-in').item.json; } catch (e) { /* ignore */ } }
if (!base) throw new Error('missing assembled lead data');
const okp = $json;
const affected = Number(okp.affectedRows ?? 0);
const leadId = Number(okp.insertId ?? 0);
const reopen = affected >= 2;
const BRAND_TH = { mazda: 'Mazda', ford: 'Ford', mitsubishi: 'Mitsubishi', gwm: 'GWM', deepal: 'Deepal', kia: 'Kia' };
const srcLabel = ({ facebook: 'Facebook Lead Ad', messenger: 'Messenger', walkin: 'Walk-in form' })[base.source] || base.source;
const row = (label, value) => ({ type: 'box', layout: 'baseline', spacing: 'sm', contents: [
  { type: 'text', text: label, size: 'sm', color: '#8C8C8C', flex: 2 },
  { type: 'text', text: String(value || '-'), size: 'sm', color: '#222222', flex: 5, wrap: true }
] });
const bubble = { type: 'bubble',
  header: { type: 'box', layout: 'vertical', backgroundColor: '#06C755', paddingAll: '12px', contents: [
    { type: 'text', text: reopen ? '🔁 ลูกค้าเดิมทักซ้ำ' : '🚗 ลีดใหม่', weight: 'bold', color: '#FFFFFF', size: 'md' },
    { type: 'text', text: (BRAND_TH[base.brand] || base.brand) + ' · สาขา ' + base.branchCode, color: '#E8FFE8', size: 'xs' }
  ] },
  body: { type: 'box', layout: 'vertical', spacing: 'md', contents: [
    row('ชื่อ', base.customerName), row('โทร', base.phone), row('รุ่นที่สนใจ', base.modelInterest),
    row('งบประมาณ', base.budgetRange), row('ที่มา', srcLabel),
    row('ข้อความ', base.rawMessage ? String(base.rawMessage).slice(0, 200) : '-')
  ] },
  footer: { type: 'box', layout: 'vertical', contents: [
    { type: 'text', text: 'ระบบจะส่งร่างข้อความ follow-up ให้ทุกเช้า 08:30 น. — ห้ามให้ AI ทักลูกค้าเอง เซลล์เป็นคนส่งเสมอ', size: 'xxs', color: '#8C8C8C', wrap: true }
  ] } };
const lineBody = JSON.stringify({ to: base.lineGroupId, messages: [{ type: 'flex', altText: (reopen ? '🔁 ลูกค้าเดิมทักซ้ำ: ' : '🚗 ลีดใหม่: ') + (base.customerName || 'ไม่ระบุชื่อ'), contents: bubble }] });
const esc = v => "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
const reopenSql = (reopen && leadId) ? ('INSERT INTO fun_lead_activities (lead_id, activity_type, detail) VALUES (' + leadId + ", 'reopen', " + esc('ลูกค้าเดิมทักซ้ำผ่าน ' + srcLabel) + ')') : '';
return { json: { reopen: !!reopenSql, reopenSql: reopenSql, lineBody: lineBody } };

// Normalize the walk-in form payload to the same lead shape as FB.
const b = $('Walk-in (POST)').item.json.body || {};
let phone = String(b.phone || '').replace(/[^0-9+]/g, '').replace(/^\+66/, '0');
return { json: {
  source: 'walkin',
  brand: String(b.brand || '').toLowerCase().trim(),
  branchCode: String(b.branchCode || b.branch || '').trim(),
  customerName: String(b.name || '').trim() || null,
  phone: phone || null,
  modelInterest: String(b.model || '').trim() || null,
  budgetRange: String(b.budget || '').trim() || null,
  rawMessage: String(b.message || '').trim() || null,
  consent: b.consent ? 1 : 0
} };

const ch = $json;
const lead = $('Normalize Walk-in').item.json;
const esc = v => (v === null || v === undefined || v === '') ? 'NULL' : "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
const consentFlag = lead.consent ? 1 : 0;
const sql = "INSERT INTO fun_leads (source, fb_leadgen_id, fb_page_id, brand, branch_code, customer_name, phone, model_interest, budget_range, raw_message, status, consent_flag, consent_date, next_followup_date) VALUES ('walkin', NULL, NULL, " + [esc(ch.brand), esc(ch.branch_code), esc(lead.customerName), esc(lead.phone), esc(lead.modelInterest), esc(lead.budgetRange), esc(lead.rawMessage)].join(', ') + ", 'new', " + consentFlag + ', ' + (consentFlag ? 'NOW()' : 'NULL') + ", CURDATE()) ON DUPLICATE KEY UPDATE status='new', next_followup_date=CURDATE(), updated_at=NOW(), lead_id=LAST_INSERT_ID(lead_id)";
return { json: { ...lead, brand: ch.brand, branchCode: ch.branch_code, fbPageName: ch.fb_page_name, lineGroupId: ch.line_group_id, gsheetId: ch.gsheet_id, sql: sql } };
